name: Deploy to main

on:
  push:
    branches:
      - main
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, self-hosted-kamakshimoney]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4

      - name: Deploy latest code
        run: |
          echo ">>> Switching to project directory"
          cd /home/ubuntu/api_code/crm-kamakshimoney-frontend

          echo ">>> Fetching latest code from master branch"
          git pull origin main

          echo ">>> Install dependency"
          npm install --legacy-peer-deps
          CI=false npm run build

          echo ">>> rm from s3"
          aws s3 rm s3://crm.kamakshimoney.com --recursive

          echo ">>> upload on s3"
          aws s3 cp build/ s3://crm.kamakshimoney.com/ --recursive

          aws cloudfront create-invalidation --distribution-id E3KVVACOIT7Q7W --paths "/*" --profile default

          echo ">>> Showing last 10 commits"
          git log -10 --oneline
          echo ">>> Deployment completed successfully!"



