.form-error-message-wrapper {
    display: none;
    position: absolute;
    font-size: 10px;
    padding: 5px 12px;
    color: #D94948;
    background: #fff;
    border-radius: 20px;
    margin: auto;
    transition: 0.8s 0.2s;
    border: 1px solid #e5e5ea;
    top: calc(100% - 3px);
    z-index: 10;
    -webkit-filter: drop-shadow(0 0 6px rgba(0,0,0,.1));
    filter: drop-shadow(0 0 6px rgba(0,0,0,.1));

    &.form-error-message-show {
        // -webkit-animation-duration: .3s;
        // animation-duration: .3s;
        // -webkit-animation-timing-function: ease-out;
        // animation-timing-function: ease-out;
        display: block
    }

    .triangle-border {
        position: absolute;
        width: 0;
        height: 0;
        top: -5px;
        left: 12px;
        &::before {
            content: '';
            position: absolute;
            top: -1px; /* adjust for border thickness */
            left: -1px;
            width: 0;
            height: 0;
            border-left: 7px solid transparent;   /* 8px + 1px border */
            border-right: 7px solid transparent;
            border-bottom: 7px solid #e5e5ea;       /* border color */
        }
        .triangle-inner {
          position: absolute;
          top: 0;
          left: 0;
          width: 0;
          height: 0;
          border-left: 6px solid transparent;
          border-right: 6px solid transparent;
          border-bottom: 6px solid #fff;
          z-index: 1;
        }
      }
      
}



