// Header CSS
.header {
  background-color: #ffffff;
  padding: 12px;
  border-radius: 15px;
  display: flex;
  justify-content: space-between;
  align-items: center;

  .search {
    width: 50%;

    .searchInner {
      width: 100%;
      position: relative;
      background-color: #f7f7fa;
      border-radius: 5px;
    }

    .icon {
      position: absolute;
      top: 10px;
      left: 10px;
    }

    .dropdownMenu {
      position: absolute;
      top: 0;
      right: 0;
    }

    input {
      background-color: #f7f7fa;
      border: none;
      height: 36px;
      padding-left: 35px;

      &:focus {
        outline: 0px solid !important;
        border-color: #f7f7fa;
      }
    }

    .autoComplete {
      position: absolute;
      background-color: #ffffff;
      border-radius: 10px;
      left: 0;
      width: 90%;
      top: 38px;
      box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
      z-index: 99999;
    }

    .list {
      padding: 12px 20px;
      border-bottom: 1px solid #e5e5e5;
      cursor: pointer;
    }
  }

  .user {
    display: flex;
    align-items: center;
  }

  .notification {
    width: 40px;
    height: 40px;
    background-color: #f6f6f6;
    border-radius: 5px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 20px;
  }

  .userInfo {
    display: flex;
    align-items: flex-end;
    margin-left: 12px;
  }

  .userName {
    margin-left: 7px;

    p {
      font-size: 14px;
      font-weight: bold;
      margin-bottom: 2px;
    }

    div {
      background-color: #f6f6f6;
      font-size: 11px;
      padding: 2px 6px;
      border-radius: 20px;
    }
  }
}



