  font-weight: bold;
  font-size: 15px;
  margin-top: -5px;
}

.sidebar {
  // background-color: #bc0f1d;
  background-color: var(--brand-color-darker-900);
  position: fixed;
  left: 0;
  z-index: 10;
}

.sidebar__body {
  overflow-y: auto;
  position: relative;
}

.sidebar__body::-webkit-scrollbar {
  width: 6px;
}

.sidebar__body:hover::-webkit-scrollbar {
  width: 6px;
  transition: width 0.2s ease-in-out;
}

.sidebar__body::-webkit-scrollbar-thumb {
  background-color: rgb(from var(--brand-color) r g b / 85%);
  border-radius: 10px;
}

.sidebar__body::-webkit-scrollbar-thumb:hover {
  background-color: rgb(from var(--brand-color) r g b / 55%);
}

.sidebar__body::-webkit-scrollbar-track {
  background-color: var(--brand-color-darker-900);
}

@media (max-width: 992px) {
  .sidebar__body {
    overflow: inherit;
  }
}



