// User Info Styles
.user-info-card {
  background-color: #ffffff;
  padding: 12px;
  border-radius: 15px;
  margin: 12px 0;

  .customer-img {
    width: 76px;
    height: 75px;
    border-radius: 6px;
  }

  .name {
    font-size: 16px;
    text-transform: capitalize;
  }

  .identity {
    background: rgba(229, 229, 229, 0.25);
    padding: 8px 15px;
    border-radius: 10px;

    h6 {
      font-size: 14px;
      margin-bottom: 8px;
    }
  }

  .lender-name-block {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    // margin-top: 5px;

    .name-block {
      position: relative;
    }

    .name {
      font-size: 10px;
      font-weight: bold;
      padding: 0 7px;
      position: relative;
      z-index: 999;
    }

    .background {
      opacity: 0.1;
      padding: 11px 0;
      position: absolute;
      width: 100%;
      top: -2px;
      z-index: 0;
      right: 0px;
      z-index: 0;
      border-radius: 3px;
    }
  }

  .user_id {
    width: fit-content;
    padding: 3px 10px 3px 10px;
    margin-top: 3px;
    border-radius: 16px;
    display: flex;
    align-items: center;
    font-size: 10px;
  }

  .btn-approved {
    width: 100%;
    height: 52px;
    padding: 14px 10px;
    border-radius: 16px;
    background: var(--brand-color);
    color: #fff;
    margin-top: 7px;

    &:hover {
      background: var(--brand-color-darker-900);
    }

    &:disabled {
      background-color: #d3d3d3;
      color: #696969;
    }
  }

  .bottom-info {
    border-top: 1px solid #dddddd;
    padding: 12px 12px 0 12px;
    margin-top: 15px;
    margin-left: -12px;
    margin-right: -12px;
  }
  .button-group-right {
  display: flex;
  justify-content: flex-end; 
  gap: 10px; 
  flex-wrap: wrap;
  align-items: center;
}
.blacklisted-message {
  background-color: #ffe5ec;
  font-size: 11px;
  padding: 12px 6px; 
  border-radius: 4px;
  color: red;
}
.send-allign-button {
  font-size: 11px;
}
.add-to-blacklist{
  font-size: 11px;
}

}
.text-center-modal {
  text-align: center;
  font-size: 14px;
}



