// Breakpoints
@mixin screen-max($breakpoint) {
  @media (max-width: $breakpoint) {
    @content;
  }
}

@mixin screen-min($breakpoint) {
  @media (min-width: $breakpoint) {
    @content;
  }
}

.button {
  font-size: 16px;
  @include screen-max($md) {
    font-size: 14px;
  }
}



// Customize CSS

.pagination .page-link:hover {
  background-color: #f3f4fa !important;
  border-color: #e1dede !important;
  color: #0d6efd !important;
}

.rs-heading {
  font-weight: 600;
}

.rs-picker-toggle-wrapper {
  display: block;
}



// Mixins

@mixin flexbox($justify: center, $align: center, $direction: row) {
  display: flex;
  justify-content: $justify;
  align-items: $align;
  flex-direction: $direction;
}

@mixin center($type: absolute) {
  position: $type;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

@mixin border-radius($radius) {
  -webkit-border-radius: $radius;
  -moz-border-radius: $radius;
  border-radius: $radius;
}

@mixin text-truncate {
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}



/*------------------------------------------
 Positions
------------------------------------------*/

.position-relative {
  position: relative;
}
.position-absolute {
  position: absolute;
}
.position-static {
  position: static;
}

// Backgrounds Utilities
.bg-white {
  background-color: #ffffff;
}
.bg-primary {
  background-color: #182bda;
}
.bg-gray {
  background-color: #9f9f9f;
}
.bg-mid-gray {
  background-color: #f1f1f1;
}
.bg-light-gray {
  background-color: #f9f9f9;
}
.bg-green {
  background-color: #0ebb53;
}
.bg-red {
  background-color: #f33c3c;
}
.bg-gold {
