  --rs-color-focus-ring: rgb(from var(--brand-color) r g b / 25%);

  --rs-btn-ghost-border: var(--brand-color);
  --rs-btn-ghost-hover-border: var(--brand-color);
  --rs-btn-ghost-active-border: var(--brand-color-darker);
  --rs-btn-ghost-text: var(--brand-color);
  --rs-btn-ghost-hover-text: var(--brand-color-darker);
  --rs-btn-ghost-active-text: var(--brand-color-darker);

  --rs-listbox-option-hover-bg: rgb(from var(--brand-color) r g b / 15%);
  --rs-listbox-option-hover-text: rgb(from var(--brand-color) r g b / 85%);

  --rs-picker-value: #343434;
}

// .rs-btn-blue:not(.filters-wrapper .rs-btn-blue), .rs-btn-primary:not(.filters-wrapper .rs-btn-blue) {
//   --rs-btn-primary-bg: var(--brand-color);
