//   --rs-btn-primary-active-bg: var(--brand-color-darker-900);
// }

.rs-btn-primary{
  --rs-btn-primary-bg: var(--brand-color);
  --rs-btn-primary-hover-bg: var(--brand-color-darker-900);
  --rs-btn-primary-active-bg: var(--brand-color-darker-900);
}

.rs-btn-primary.rs-btn-red {
  --rs-btn-primary-bg: #FFC200;
  --rs-btn-primary-hover-bg: #d5a507;
  --rs-btn-primary-active-bg: #d5a507;
}

.rs-picker-default:not(.rs-picker-disabled) .rs-picker-toggle-active, 
.rs-picker-default:not(.rs-picker-disabled) .rs-picker-toggle:focus, 
.rs-picker-default:not(.rs-picker-disabled) .rs-picker-toggle:hover {
  border-color: var(--brand-color);
  box-shadow: 0 0 0 3px rgb(from var(--brand-color) r g b / 25%);
}


body {
  background-color: #f6f6f6;
  font-family: "Poppins", serif;
  font-weight: normal;
  font-size: 13px;
}

a:hover {
  text-decoration: none !important;
}

.text-start {
  text-align: start;
}

.justify-start {
  display: flex;
  justify-content: start;
}
.justify-between {
  display: flex;
  justify-content: space-between;
}
.justify-end {
  display: flex;
  justify-content: right;
}
.rs-picker-toggle {
  display: flex !important;
  justify-content: start !important;
}
.flex {
  display: flex;
}
.m-10 {
  margin: 10px;
}
.bg_gray {
  background: #e5e5e542;
}
.flex-col {
  display: flex;
  flex-direction: column;
}
.align-center {
  display: flex;
  align-items: center;
}

img {
  max-width: 100%;
  display: block;
  height: auto;
}

.mr-auto {
  margin: 0 auto;
}

// .rs-sidenav-inverse .rs-dropdown-item.rs-dropdown-item-active,
