.rs-sidenav-inverse,
.rs-sidenav-inverse .rs-dropdown .rs-dropdown-toggle,
.rs-sidenav-inverse .rs-dropdown-item-submenu:hover > .rs-dropdown-item-toggle,
.rs-sidenav-inverse .rs-sidenav-item,
.rs-sidenav-inverse .rs-sidenav-toggle-button {
  background-color: var(--brand-color-darker-900);
}

.rs-sidenav-nav > .rs-dropdown .rs-dropdown-toggle,
.rs-sidenav-nav > .rs-sidenav-item {
  font-size: 14px;
  // padding-left: 50px;
}

.rs-sidenav-nav .rs-dropdown-item {
  font-size: 13px;
  color: #a3aed1;
}

.rs-sidenav-inverse .rs-dropdown-item.rs-dropdown-item-active,
.rs-sidenav-inverse .rs-sidenav-item.rs-sidenav-item-active {
  color: #ffffff;
  font-weight: 400;
}

.rs-sidenav-item:hover,
.rs-sidenav-item:focus,
.rs-sidenav-item-active {
  background-color: var(--brand-color-darker) !important;
}

.rs-dropdown-item:hover {
  background-color: transparent !important;
}

.sidebar__body .rs-dropdown-expand .rs-dropdown-toggle {
  background-color: var(--brand-color-darker) !important;
}

.sidebar__body .rs-dropdown-item-active,
.sidebar__body .rs-dropdown-menu {
  background-color: var(--brand-color-darker-800) !important;
}

.rs-dropdown-item {
  & .rs-icon {
    width: 7px;
    margin-right: 4px;
  }
}

.vertical-spacing-5 {
  margin-top: 5px;
  margin-bottom: 5px;
}

.vertical-spacing-10 {
  margin-top: 10px;
  margin-bottom: 10px;
}

.vertical-spacing-15 {
  margin-top: 15px;
  margin-bottom: 15px;
}

.vertical-spacing-20 {
  margin-top: 20px;
  margin-bottom: 20px;
}

// Badge
.badge {
  padding: 3px 8px;
  background-color: #f1f1f1;
  font-size: 12px;
  border-radius: 4px;

  &.rounded {
    border-radius: 12px;
    padding: 4px 10px;
  }

  &.purple {
    background-color: rgba(60, 129, 246, 0.1);
    color: rgba(60, 129, 246, 1);
  }
}

.rs-picker-check .rs-stack{
  max-width: 100% !important;
}



